import { MessageEvent } from '@nitrots/nitro-renderer';
import { TimeOfDayParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/TimeOfDayParser';

export class TimeOfDayEvent extends MessageEvent {
    constructor(callback: (event: TimeOfDayEvent) => void) {
        super(callback, TimeOfDayParser);
    }

    public getParser(): TimeOfDayParser {
        return this.parser as TimeOfDayParser;
    }
}
